def _sanitize_endpoint(path):
    """
    Sanitize endpoint path to prevent high-cardinality label values.
    Unknown paths are grouped under 'other' to prevent metric explosion attacks.
    """
    if path in KNOWN_ENDPOINTS:
        return path

    for prefix in KNOWN_PREFIXES:
        if path.startswith(prefix):
            return prefix + "{param}"

    return "/other"


